@import url('https://fonts.googleapis.com/css2?family=Work+Sans&display=swap');

.theme-fandomdesktop-dark, .theme-fandomdesktop-light {
    --theme-body-background-image: url('https://static.wikia.nocookie.net/backrooms/images/4/42/174-1.webp/revision/latest/scale-to-width-down/340?cb=20260604183731&format=original');
}
.theme-fandomdesktop-light {
    --theme-page-background-color: #2d3040;
    --theme-page-background-color--secondary: #1c2745;
    --theme-page-text-color: #d4d3cf;
    --theme-page-accent-mix-color: #2d3040;
    --theme-community-header-color: #ffffff;
    --theme-link-color: #6d91f2;
	--theme-accent-color: #6d91f2;
    --theme-accent-label-color: #ffffff;
    --theme-border-color: #6d91f2;
	--theme-sticky-nav-background-color: #361912;
    --quote: #46475d;
    --bquote: #7d6766;
    --dot-dot: rgba(40, 45, 58, 0.9);
    --shadow: #191211;

    .darkblock {
      background-color: transparent;
      backdrop-filter: brightness(0.47);
      color: var(--theme-page-background-color);
    }
    .darkblock h1, .darkblock h2, .darkblock h3, .darkblock h4 {
      filter: brightness(2);
    }
}

.theme-fandomdesktop-dark {
    --theme-page-background-color: #2d3040;
    --theme-page-background-color--secondary: #1c2745;
    --theme-page-text-color: #d4d3cf;
    --theme-page-accent-mix-color: #2d3040;
    --theme-community-header-color: #ffffff;
    --theme-link-color: #6d91f2;
	--theme-accent-color: #6d91f2;
    --theme-accent-label-color: #ffffff;
    --theme-border-color: #6d91f2;
	--theme-sticky-nav-background-color: #361912;
    --quote: #46475d;
    --bquote: #7d6766;
    --dot-dot: rgba(40, 45, 58, 0.9);
    --shadow: #191211;

    .darkblock {
      background-color: transparent;
      backdrop-filter: brightness(0.8);
    }
}
html .resizable-container, .page {
  Font-family: 'Work Sans', Sans-serif;
}
.page-content {
  text-align: justify;
}
.page, .fandom-community-header {
  animation: fadeup 1s ease-in-out;
}
@keyframes fadeup {
  from {
    transform: translateY(15px);
    opacity: 0;
  }
  to {
    transform: translateY(0);
    opacity: 1;
  }
}
.styled-quote {
  background-color: var(--quote) !important;
  border-color: var(--bquote) !important;
}
h1 {
    font-weight: 600;
    color: var(--theme-link-color);
    background-image: linear-gradient(370deg, var(--theme-page-background-color--secondary), transparent);
}
.page-content h1, .page-content h2, .page-content h3 {
    font-family: 'Georgia', Serif;
    font-weight: 600;
    color: var(--theme-link-color);
}
.customhead {
    border-left: 2px solid var(--theme-border-color);
    font-size: 25px;
    padding-left: 15px;
    display: inline-block;
    margin: 0.3em;
    font-family: 'Georgia', Serif;
    border-bottom: 2px groove var(--theme-link-color);
    font-weight: 600;
}
.cheadbg {
    background: linear-gradient(370deg, var(--theme-page-background-color), transparent);
    margin: 0.9em 0;
}
.theme-fandomdesktop-dark .fandom-community-header,
.theme-fandomdesktop-light .fandom-community-header {
    background-image: linear-gradient(transparent, var(--theme-page-background-color));
    margin-bottom: -12px;
    padding: 1em 2em;
    font-family: 'Georgia', Serif;
}
.parent {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    grid-template-rows: repeat(2, 1fr);
    gap: 8px;
}
.t {
    will-change: transform;
    transition-duration: 0.5s;
}
.t:hover {
    transform: scale(105%);
}
.div1 {
    grid-row: span 2 / span 2;
    grid-column-start: 2;
    grid-row-start: 1;
    background-image: url('https://static.wikia.nocookie.net/backrooms/images/4/42/174-1.webp/revision/latest/scale-to-width-down/340?cb=20260604183731&format=original') !important;
    filter: contrast(70%);
    color: #07151f;
    text-shadow: -2px -2px 0 #ccbfb7, 2px -2px 0 #ccbfb7, -2px  2px 0 #ccbfb7, 2px  2px 0 #ccbfb7;
    background-size: cover !important;
    will-change: transform;
    transition-duration: 0.5s;
}
.div1:hover {
    transform: scale(105%);
}
.div2 {
    grid-column-start: 3;
    grid-row-start: 1;
}

.div3 {
    grid-column-start: 3;
    grid-row-start: 2;
}

.div4 {
    grid-column-start: 1;
    grid-row-start: 1;
}

.div5 {
    grid-column-start: 1;
    grid-row-start: 2;
}

.right-rail-wrapper, .page__main, .lightblock, .styled-quote {
	background-image: radial-gradient(var(--dot-dot) 1px, transparent 1px), radial-gradient(var(--dot-dot) 1px, transparent 1px);
	background-size: 30px 30px;
	background-position: 0 0, 15px 15px;
}

.rail-module {
	background: none;
}
.line-top {
    display: block;
    height: 5px;
    background: linear-gradient(to right, transparent, transparent, var(--theme-border-color), var(--theme-page-text-color), var(--theme-border-color), transparent, transparent);
    border-bottom: 2px solid var(--theme-border-color);
    margin: 1em;
}
.line-bottom {
    display: block;
    height: 5px;
    background: linear-gradient(to right, transparent, transparent, var(--theme-border-color), var(--theme-page-text-color), var(--theme-border-color), transparent, transparent);
    border-top: 2px solid var(--theme-border-color);
    margin: 1em;
}
a {
  text-decoration: none;
  background-image: linear-gradient(to right, var(--theme-link-color), var(--theme-link-color), transparent);
  background-size: 0% 5px;
  background-repeat: no-repeat;
  background-position: left bottom;
  padding-bottom: 2px;
  transition: background-size 0.3s ease-out;
}

a:hover,
a:focus-visible {
  background-size: 100% 2px;
  text-decoration: none;
  font-weight: bold;
}

.cred {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  grid-template-rows: 1fr;
  grid-column-gap: 5px;
  grid-row-gap: 5px;
  text-align: left;
  border-bottom: 1px solid var(--theme-border-color);
}
.cred2 {
  padding: 15px 0;
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  grid-template-rows: 2fr;
  grid-column-gap: 5px;
  grid-row-gap: 5px;
  text-align: left;
  border-bottom: 1px solid var(--theme-border-color);
}
.bl1 { grid-area: 1 / 1 / 2 / 2; }
.bl2 { grid-area: 1 / 2 / 2 / 3; }

.bl3 { grid-area: 1 / 1 / 2 / 2; }
.bl4 { grid-area: 1 / 2 / 2 / 3; }

.titleblock {
  border-color: var(--theme-page-accent-mix-color);
  background-color: var(--quote);
}

.sensitive-image {
  display: inline-block;
  position: relative;
  border-radius: 5px;
  border: 1px solid var(--theme-border-color);
  transform: scale(1);
  will-change: transform;
  transition: 0.3s ease-in-out;
  overflow: hidden;
}
.sensitive-image:hover {
  transform: scale(1.1);
}
.hover-sensitive-image {
  position: absolute;
  width: 100%;
  height: 100%;
  border-radius: 5px;
  backdrop-filter: blur(17px);
  background: var(--theme-page-background-color);
  display: flex;
  text-align: center;
  justify-content: center;
  align-items: center;
  flex-direction: column;
  font-size: 20px;
  font-weight: 900;
  top: 0;
  right: 0;
  transition: 1s ease forwards;
}
.hover-sensitive-image:hover {
  backdrop-filter: blur(5px);
}
.sensitive-image-caption {
  position: absolute;
  width: 100%;
  height: fit-content;
  backdrop-filter: blur(5px) brightness(0.7);
  color: white;
  border: 1px solid var(--theme-border-color);
  bottom: 0;
  ri ght: 0;
  padding: 5px;
}

